import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testGetRecordSeparator() throws Exception {
        // Create a mock CSVFormat object
        CSVFormat csvFormat = mock(CSVFormat.class);

        // Set up the expected record separator
        String expectedRecordSeparator = "\r\n";

        // Set the record separator using reflection
        Field recordSeparatorField = CSVFormat.class.getDeclaredField("recordSeparator");
        recordSeparatorField.setAccessible(true);
        recordSeparatorField.set(csvFormat, expectedRecordSeparator);

        // Invoke the getRecordSeparator method using reflection
        String actualRecordSeparator = csvFormat.getRecordSeparator();

        // Verify the result
        assertEquals(expectedRecordSeparator, actualRecordSeparator);
    }
}
